     1→/**
     2→ * Service Demand Routes
     3→ *
     4→ * REST endpoints for managing fleet service demand requirements.
     5→ * Service demand defines minimum train availability constraints for
     6→ * the optimizer - a HARD CONSTRAINT that cannot be violated.
     7→ *
     8→ * @see specs/005-api.md Section 5.9
     9→ * @see specs/004-domain-services.md Section 4.2.6
    10→ */
    11→
    12→import { Hono } from 'hono';
    13→import {
    14→  success,
    15→  paginatedSuccess,
    16→  error,
    17→  parsePaginationQuery,
    18→  ErrorCodes,
    19→  type AppVariables,
    20→} from '../types';
    21→import { getRequestId, getRequestDuration } from '../middleware/request-context';
    22→import {
    23→  getServiceDemandService,
    24→  type CreateDemandRequest,
    25→  type DemandListFilters,
    26→  type ProposedPM,
    27→} from '../../services/service-demand';
    28→import { isValidUuid } from '../../lib/schemas';
    29→
    30→// Singleton service instance
    31→let serviceDemandService: ReturnType<typeof getServiceDemandService> | null = null;
    32→
    33→function getService(): ReturnType<typeof getServiceDemandService> {
    34→  if (!serviceDemandService) {
    35→    serviceDemandService = getServiceDemandService();
    36→  }
    37→  return serviceDemandService;
    38→}
    39→
    40→export const serviceDemandRoutes = new Hono<{ Variables: AppVariables }>();
    41→
    42→// =============================================================================
    43→// Demand Queries
    44→// =============================================================================
    45→
    46→/**
    47→ * GET /service-demand/:fleetId/:date
    48→ *
    49→ * Get service demand configuration for a fleet on a specific date.
    50→ * This is the primary endpoint for the optimizer to determine minimum
    51→ * train availability requirements.
    52→ *
    53→ * Path params:
    54→ * - fleetId: string - UUID of the fleet
    55→ * - date: string - Target date (YYYY-MM-DD)
    56→ *
    57→ * Query params:
    58→ * - holidays: string (optional) - Comma-separated list of holiday dates
    59→ */
    60→serviceDemandRoutes.get('/service-demand/:fleetId/:date', async (c) => {
    61→  const requestId = getRequestId(c);
    62→  const fleetId = c.req.param('fleetId');
    63→  const date = c.req.param('date');
    64→
    65→  if (!isValidUuid(fleetId)) {
    66→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid fleet ID format', requestId), 400);
    67→  }
    68→
    69→  // Validate date format
    70→  const dateRegex = /^\d{4}-\d{2}-\d{2}$/;
    71→  if (!dateRegex.test(date)) {
    72→    return c.json(
    73→      error(ErrorCodes.VALIDATION_ERROR, 'Date must be in YYYY-MM-DD format', requestId),
    74→      400
    75→    );
    76→  }
    77→
    78→  const holidaysParam = c.req.query('holidays');
    79→  const holidays = holidaysParam ? holidaysParam.split(',') : undefined;
    80→
    81→  const service = getService();
    82→  const demand = await service.getDemand(fleetId, date, holidays);
    83→
    84→  return c.json(
    85→    success({
    86→      fleetId: demand.fleetId,
    87→      fleetCode: demand.fleetCode,
    88→      date: demand.date,
    89→      dayType: demand.dayType,
    90→      minTrainsRequired: demand.minTrainsRequired,
    91→      standbyBuffer: demand.standbyBuffer,
    92→      totalRequired: demand.totalRequired,
    93→      peakAmRequirement: demand.peakAmRequirement,
    94→      middayRequirement: demand.middayRequirement,
    95→      peakPmRequirement: demand.peakPmRequirement,
    96→      eveningRequirement: demand.eveningRequirement,
    97→      source: demand.source,
    98→    })
    99→  );
   100→});
   101→
   102→/**
   103→ * POST /service-demand/validate
   104→ *
   105→ * Validate fleet availability against service demand.
   106→ * Returns whether the proposed schedule would violate minimum availability.
   107→ *
   108→ * Body:
   109→ * - fleetId: string (required) - UUID of the fleet
   110→ * - targetDate: string (required) - Date to validate (YYYY-MM-DD)
   111→ * - additionalUnavailable: number (optional) - Number of additional trains that would be unavailable
   112→ * - holidays: string[] (optional) - Array of holiday dates
   113→ */
   114→serviceDemandRoutes.post('/service-demand/validate', async (c) => {
   115→  const requestId = getRequestId(c);
   116→  const body = await c.req.json();
   117→
   118→  if (!body.fleetId || !isValidUuid(body.fleetId)) {
   119→    return c.json(
   120→      error(ErrorCodes.VALIDATION_ERROR, 'Valid fleetId is required', requestId),
   121→      400
   122→    );
   123→  }
   124→
   125→  if (!body.targetDate) {
   126→    return c.json(
   127→      error(ErrorCodes.VALIDATION_ERROR, 'targetDate is required', requestId),
   128→      400
   129→    );
   130→  }
   131→
   132→  const dateRegex = /^\d{4}-\d{2}-\d{2}$/;
   133→  if (!dateRegex.test(body.targetDate)) {
   134→    return c.json(
   135→      error(ErrorCodes.VALIDATION_ERROR, 'targetDate must be in YYYY-MM-DD format', requestId),
   136→      400
   137→    );
   138→  }
   139→
   140→  const service = getService();
   141→  const validation = await service.validateAvailability(
   142→    body.fleetId,
   143→    body.targetDate,
   144→    body.additionalUnavailable ?? 0,
   145→    body.holidays
   146→  );
   147→
   148→  return c.json(
   149→    success({
   150→      isValid: validation.isValid,
   151→      fleetId: validation.fleetId,
   152→      date: validation.date,
   153→      dayType: validation.dayType,
   154→      totalTrains: validation.totalTrains,
   155→      fitTrains: validation.fitTrains,
   156→      unavailableTrains: validation.unavailableTrains,
   157→      inMaintenanceTrains: validation.inMaintenanceTrains,
   158→      additionalUnavailable: validation.additionalUnavailable,
   159→      availableTrains: validation.availableTrains,
   160→      required: validation.required,
   161→      surplus: validation.surplus,
   162→      severity: validation.severity,
   163→      message: validation.message,
   164→    })
   165→  );
   166→});
   167→
   168→/**
   169→ * POST /service-demand/validate-pm
   170→ *
   171→ * Validate a proposed PM schedule against service demand.
   172→ * Checks if scheduling the specified PMs would violate availability.
   173→ *
   174→ * Body:
   175→ * - fleetId: string (required) - UUID of the fleet
   176→ * - proposedPMs: array (required) - Array of proposed PM schedules
   177→ *   - trainId: string (required) - UUID of the train
   178→ *   - targetDate: string (required) - PM target date (YYYY-MM-DD)
   179→ *   - pmCode: string (optional) - PM type code for better error messages
   180→ * - holidays: string[] (optional) - Array of holiday dates
   181→ */
   182→serviceDemandRoutes.post('/service-demand/validate-pm', async (c) => {
   183→  const requestId = getRequestId(c);
   184→  const body = await c.req.json();
   185→
   186→  if (!body.fleetId || !isValidUuid(body.fleetId)) {
   187→    return c.json(
   188→      error(ErrorCodes.VALIDATION_ERROR, 'Valid fleetId is required', requestId),
   189→      400
   190→    );
   191→  }
   192→
   193→  if (!Array.isArray(body.proposedPMs) || body.proposedPMs.length === 0) {
   194→    return c.json(
   195→      error(ErrorCodes.VALIDATION_ERROR, 'proposedPMs array is required', requestId),
   196→      400
   197→    );
   198→  }
   199→
   200→  // Validate proposed PMs
   201→  for (const pm of body.proposedPMs) {
   202→    if (!pm.trainId || !isValidUuid(pm.trainId)) {
   203→      return c.json(
   204→        error(ErrorCodes.VALIDATION_ERROR, 'Each proposedPM requires a valid trainId', requestId),
   205→        400
   206→      );
   207→    }
   208→    if (!pm.targetDate) {
   209→      return c.json(
   210→        error(ErrorCodes.VALIDATION_ERROR, 'Each proposedPM requires a targetDate', requestId),
   211→        400
   212→      );
   213→    }
   214→  }
   215→
   216→  const service = getService();
   217→  const proposedPMs: ProposedPM[] = body.proposedPMs.map((pm: {
   218→    trainId: string;
   219→    targetDate: string;
   220→    pmCode?: string;
   221→    pmTypeId?: string;
   222→    durationDays?: number;
   223→  }) => ({
   224→    trainId: pm.trainId,
   225→    targetDate: pm.targetDate,
   226→    pmCode: pm.pmCode,
   227→    pmTypeId: pm.pmTypeId,
   228→    durationDays: pm.durationDays,
   229→  }));
   230→
   231→  const violations = await service.findViolations(body.fleetId, proposedPMs, body.holidays);
   232→
   233→  return c.json(
   234→    success({
   235→      isValid: violations.length === 0,
   236→      violations: violations.map((v) => ({
   237→        date: v.date,
   238→        dayType: v.dayType,
   239→        trainId: v.trainId,
   240→        trainNumber: v.trainNumber,
   241→        pmCode: v.pmCode,
   242→        required: v.required,
   243→        available: v.available,
   244→        shortfall: v.shortfall,
   245→        severity: v.severity,
   246→        message: v.message,
   247→      })),
   248→      totalViolations: violations.length,
   249→    })
   250→  );
   251→});
   252→
   253→/**
   254→ * POST /service-demand/validate-horizon
   255→ *
   256→ * Validate service demand for a date range (planning horizon).
   257→ * Checks existing scheduled PMs against demand for the entire range.
   258→ *
   259→ * Body:
   260→ * - fleetId: string (required) - UUID of the fleet
   261→ * - startDate: string (required) - Start date (YYYY-MM-DD)
   262→ * - horizonDays: number (required) - Number of days to check
   263→ * - holidays: string[] (optional) - Array of holiday dates
   264→ */
   265→serviceDemandRoutes.post('/service-demand/validate-horizon', async (c) => {
   266→  const requestId = getRequestId(c);
   267→  const body = await c.req.json();
   268→
   269→  if (!body.fleetId || !isValidUuid(body.fleetId)) {
   270→    return c.json(
   271→      error(ErrorCodes.VALIDATION_ERROR, 'Valid fleetId is required', requestId),
   272→      400
   273→    );
   274→  }
   275→
   276→  if (!body.startDate) {
   277→    return c.json(
   278→      error(ErrorCodes.VALIDATION_ERROR, 'startDate is required', requestId),
   279→      400
   280→    );
   281→  }
   282→
   283→  if (!body.horizonDays || body.horizonDays < 1 || body.horizonDays > 365) {
   284→    return c.json(
   285→      error(ErrorCodes.VALIDATION_ERROR, 'horizonDays must be between 1 and 365', requestId),
   286→      400
   287→    );
   288→  }
   289→
   290→  const service = getService();
   291→  const violations = await service.findViolationsInHorizon(
   292→    body.fleetId,
   293→    body.startDate,
   294→    body.horizonDays,
   295→    body.holidays
   296→  );
   297→
   298→  return c.json(
   299→    success({
   300→      isValid: violations.length === 0,
   301→      startDate: body.startDate,
   302→      horizonDays: body.horizonDays,
   303→      violatedDates: violations.map((v) => ({
   304→        date: v.date,
   305→        dayType: v.validation.dayType,
   306→        required: v.validation.required,
   307→        available: v.validation.availableTrains,
   308→        shortfall: Math.abs(v.validation.surplus),
   309→        severity: v.validation.severity,
   310→        message: v.validation.message,
   311→      })),
   312→      totalViolations: violations.length,
   313→    })
   314→  );
   315→});
   316→
   317→/**
   318→ * GET /service-demand/train/:trainId/can-schedule
   319→ *
   320→ * Check if a specific train can be scheduled for maintenance on a date.
   321→ *
   322→ * Path params:
   323→ * - trainId: string - UUID of the train
   324→ *
   325→ * Query params:
   326→ * - targetDate: string (required) - Date to check (YYYY-MM-DD)
   327→ * - holidays: string (optional) - Comma-separated list of holiday dates
   328→ */
   329→serviceDemandRoutes.get('/service-demand/train/:trainId/can-schedule', async (c) => {
   330→  const requestId = getRequestId(c);
   331→  const trainId = c.req.param('trainId');
   332→  const targetDate = c.req.query('targetDate');
   333→
   334→  if (!isValidUuid(trainId)) {
   335→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid train ID format', requestId), 400);
   336→  }
   337→
   338→  if (!targetDate) {
   339→    return c.json(
   340→      error(ErrorCodes.VALIDATION_ERROR, 'targetDate query param is required', requestId),
   341→      400
   342→    );
   343→  }
   344→
   345→  const holidaysParam = c.req.query('holidays');
   346→  const holidays = holidaysParam ? holidaysParam.split(',') : undefined;
   347→
   348→  const service = getService();
   349→  const result = await service.canScheduleTrainForMaintenance(trainId, targetDate, holidays);
   350→
   351→  return c.json(
   352→    success({
   353→      canSchedule: result.canSchedule,
   354→      trainId,
   355→      targetDate,
   356→      validation: {
   357→        isValid: result.validation.isValid,
   358→        dayType: result.validation.dayType,
   359→        availableTrains: result.validation.availableTrains,
   360→        required: result.validation.required,
   361→        surplus: result.validation.surplus,
   362→        severity: result.validation.severity,
   363→        message: result.validation.message,
   364→      },
   365→    })
   366→  );
   367→});
   368→
   369→// =============================================================================
   370→// Demand Configuration CRUD
   371→// =============================================================================
   372→
   373→/**
   374→ * POST /service-demand/config
   375→ *
   376→ * Create a new service demand configuration.
   377→ *
   378→ * Body:
   379→ * - fleetId: string (required) - UUID of the fleet
   380→ * - effectiveDate: string (required) - When this config becomes effective (YYYY-MM-DD)
   381→ * - dayType: string (required) - WEEKDAY | SATURDAY | SUNDAY | HOLIDAY
   382→ * - minTrainsRequired: number (required) - Minimum trains required for service
   383→ * - peakAmRequirement: number (optional) - AM peak requirement
   384→ * - middayRequirement: number (optional) - Midday requirement
   385→ * - peakPmRequirement: number (optional) - PM peak requirement
   386→ * - eveningRequirement: number (optional) - Evening requirement
   387→ * - standbyBuffer: number (optional) - Additional standby trains (default: 2)
   388→ * - notes: string (optional) - Configuration notes
   389→ */
   390→serviceDemandRoutes.post('/service-demand/config', async (c) => {
   391→  const requestId = getRequestId(c);
   392→  const body = await c.req.json();
   393→
   394→  if (!body.fleetId || !isValidUuid(body.fleetId)) {
   395→    return c.json(
   396→      error(ErrorCodes.VALIDATION_ERROR, 'Valid fleetId is required', requestId),
   397→      400
   398→    );
   399→  }
   400→
   401→  if (!body.effectiveDate) {
   402→    return c.json(
   403→      error(ErrorCodes.VALIDATION_ERROR, 'effectiveDate is required', requestId),
   404→      400
   405→    );
   406→  }
   407→
   408→  const validDayTypes = ['WEEKDAY', 'SATURDAY', 'SUNDAY', 'HOLIDAY'];
   409→  if (!body.dayType || !validDayTypes.includes(body.dayType)) {
   410→    return c.json(
   411→      error(
   412→        ErrorCodes.VALIDATION_ERROR,
   413→        `dayType must be one of: ${validDayTypes.join(', ')}`,
   414→        requestId
   415→      ),
   416→      400
   417→    );
   418→  }
   419→
   420→  if (typeof body.minTrainsRequired !== 'number' || body.minTrainsRequired < 0) {
   421→    return c.json(
   422→      error(ErrorCodes.VALIDATION_ERROR, 'minTrainsRequired must be a non-negative number', requestId),
   423→      400
   424→    );
   425→  }
   426→
   427→  const service = getService();
   428→  const request: CreateDemandRequest = {
   429→    fleetId: body.fleetId,
   430→    effectiveDate: body.effectiveDate,
   431→    dayType: body.dayType,
   432→    minTrainsRequired: body.minTrainsRequired,
   433→    peakAmRequirement: body.peakAmRequirement,
   434→    middayRequirement: body.middayRequirement,
   435→    peakPmRequirement: body.peakPmRequirement,
   436→    eveningRequirement: body.eveningRequirement,
   437→    standbyBuffer: body.standbyBuffer,
   438→    notes: body.notes,
   439→    createdBy: c.get('user')?.id,
   440→  };
   441→
   442→  const demand = await service.createDemand(request);
   443→
   444→  return c.json(
   445→    success(
   446→      {
   447→        id: demand.id,
   448→        fleetId: demand.fleetId,
   449→        effectiveDate: demand.effectiveDate,
   450→        dayType: demand.dayType,
   451→        minTrainsRequired: demand.minTrainsRequired,
   452→        peakAmRequirement: demand.peakAmRequirement,
   453→        middayRequirement: demand.middayRequirement,
   454→        peakPmRequirement: demand.peakPmRequirement,
   455→        eveningRequirement: demand.eveningRequirement,
   456→        standbyBuffer: demand.standbyBuffer,
   457→        createdAt: demand.createdAt,
   458→      },
   459→      {
   460→        timing: { durationMs: getRequestDuration(c) },
   461→      }
   462→    ),
   463→    201
   464→  );
   465→});
   466→
   467→/**
   468→ * GET /service-demand/config
   469→ *
   470→ * List service demand configurations with filtering.
   471→ *
   472→ * Query params:
   473→ * - fleetId: string (optional) - Filter by fleet UUID
   474→ * - dayType: string (optional) - Filter by day type
   475→ * - effectiveDateFrom: string (optional) - Filter by effective date range start
   476→ * - effectiveDateTo: string (optional) - Filter by effective date range end
   477→ * - page: number (optional) - Page number
   478→ * - pageSize: number (optional) - Items per page
   479→ */
   480→serviceDemandRoutes.get('/service-demand/config', async (c) => {
   481→  const service = getService();
   482→
   483→  // Parse query filters
   484→  const filters: DemandListFilters = {};
   485→  const fleetId = c.req.query('fleetId');
   486→  const dayType = c.req.query('dayType');
   487→  const effectiveDateFrom = c.req.query('effectiveDateFrom');
   488→  const effectiveDateTo = c.req.query('effectiveDateTo');
   489→
   490→  if (fleetId && isValidUuid(fleetId)) {
   491→    filters.fleetId = fleetId;
   492→  }
   493→  if (dayType) {
   494→    const validDayTypes = ['WEEKDAY', 'SATURDAY', 'SUNDAY', 'HOLIDAY'];
   495→    if (validDayTypes.includes(dayType)) {
   496→      filters.dayType = dayType as DemandListFilters['dayType'];
   497→    }
   498→  }
   499→  if (effectiveDateFrom) {
   500→    filters.effectiveDateFrom = effectiveDateFrom;
   501→  }
   502→  if (effectiveDateTo) {
   503→    filters.effectiveDateTo = effectiveDateTo;
   504→  }
   505→
   506→  const demands = await service.listDemand(filters);
   507→
   508→  // Parse pagination
   509→  const pagination = parsePaginationQuery({
   510→    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
   511→    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
   512→  });
   513→
   514→  // Apply pagination in memory
   515→  const startIndex = (pagination.page - 1) * pagination.pageSize;
   516→  const paginatedDemands = demands.slice(startIndex, startIndex + pagination.pageSize);
   517→
   518→  return c.json(
   519→    paginatedSuccess(
   520→      paginatedDemands.map((demand) => ({
   521→        id: demand.id,
   522→        fleetId: demand.fleetId,
   523→        effectiveDate: demand.effectiveDate,
   524→        dayType: demand.dayType,
   525→        minTrainsRequired: demand.minTrainsRequired,
   526→        peakAmRequirement: demand.peakAmRequirement,
   527→        middayRequirement: demand.middayRequirement,
   528→        peakPmRequirement: demand.peakPmRequirement,
   529→        eveningRequirement: demand.eveningRequirement,
   530→        standbyBuffer: demand.standbyBuffer,
   531→        notes: demand.notes,
   532→      })),
   533→      {
   534→        page: pagination.page,
   535→        pageSize: pagination.pageSize,
   536→        totalItems: demands.length,
   537→      },
   538→      { durationMs: getRequestDuration(c) }
   539→    )
   540→  );
   541→});
   542→
   543→/**
   544→ * GET /service-demand/config/:id
   545→ *
   546→ * Get a specific demand configuration by ID.
   547→ */
   548→serviceDemandRoutes.get('/service-demand/config/:id', async (c) => {
   549→  const requestId = getRequestId(c);
   550→  const id = c.req.param('id');
   551→
   552→  if (!isValidUuid(id)) {
   553→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid config ID format', requestId), 400);
   554→  }
   555→
   556→  const service = getService();
   557→  const demand = await service.getDemandById(id);
   558→
   559→  return c.json(
   560→    success({
   561→      id: demand.id,
   562→      fleetId: demand.fleetId,
   563→      effectiveDate: demand.effectiveDate,
   564→      dayType: demand.dayType,
   565→      minTrainsRequired: demand.minTrainsRequired,
   566→      peakAmRequirement: demand.peakAmRequirement,
   567→      middayRequirement: demand.middayRequirement,
   568→      peakPmRequirement: demand.peakPmRequirement,
   569→      eveningRequirement: demand.eveningRequirement,
   570→      standbyBuffer: demand.standbyBuffer,
   571→      source: demand.source,
   572→      notes: demand.notes,
   573→      createdBy: demand.createdBy,
   574→      createdAt: demand.createdAt,
   575→      updatedAt: demand.updatedAt,
   576→    })
   577→  );
   578→});
   579→
   580→/**
   581→ * PATCH /service-demand/config/:id
   582→ *
   583→ * Update a demand configuration.
   584→ *
   585→ * Body: (all optional)
   586→ * - minTrainsRequired: number
   587→ * - peakAmRequirement: number
   588→ * - middayRequirement: number
   589→ * - peakPmRequirement: number
   590→ * - eveningRequirement: number
   591→ * - standbyBuffer: number
   592→ * - notes: string
   593→ */
   594→serviceDemandRoutes.patch('/service-demand/config/:id', async (c) => {
   595→  const requestId = getRequestId(c);
   596→  const id = c.req.param('id');
   597→
   598→  if (!isValidUuid(id)) {
   599→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid config ID format', requestId), 400);
   600→  }
   601→
   602→  const body = await c.req.json();
   603→  const service = getService();
   604→
   605→  const updateData: Partial<CreateDemandRequest> = {};
   606→
   607→  if (body.minTrainsRequired !== undefined) {
   608→    if (typeof body.minTrainsRequired !== 'number' || body.minTrainsRequired < 0) {
   609→      return c.json(
   610→        error(ErrorCodes.VALIDATION_ERROR, 'minTrainsRequired must be a non-negative number', requestId),
   611→        400
   612→      );
   613→    }
   614→    updateData.minTrainsRequired = body.minTrainsRequired;
   615→  }
   616→
   617→  if (body.peakAmRequirement !== undefined) updateData.peakAmRequirement = body.peakAmRequirement;
