/**
 * Service Demand Routes
 *
 * REST endpoints for managing fleet service demand requirements.
 * Service demand defines minimum train availability constraints for
 * the optimizer - a HARD CONSTRAINT that cannot be violated.
 *
 * @see specs/005-api.md Section 5.9
 * @see specs/004-domain-services.md Section 4.2.6
 */

import { Hono } from 'hono';
import {
  success,
  paginatedSuccess,
  error,
  parsePaginationQuery,
  ErrorCodes,
  type AppVariables,
} from '../types';
import { getRequestId, getRequestDuration } from '../middleware/request-context';
import {
  getServiceDemandService,
  type CreateDemandRequest,
  type DemandListFilters,
  type ProposedPM,
} from '../../services/service-demand';
import { isValidUuid } from '../../lib/schemas';

// Singleton service instance
let serviceDemandService: ReturnType<typeof getServiceDemandService> | null = null;

function getService(): ReturnType<typeof getServiceDemandService> {
  if (!serviceDemandService) {
    serviceDemandService = getServiceDemandService();
  }
  return serviceDemandService;
}

export const serviceDemandRoutes = new Hono<{ Variables: AppVariables }>();

// =============================================================================
// Demand Queries
// =============================================================================

/**
 * GET /service-demand/:fleetId/:date
 *
 * Get service demand configuration for a fleet on a specific date.
 * This is the primary endpoint for the optimizer to determine minimum
 * train availability requirements.
 *
 * Path params:
 * - fleetId: string - UUID of the fleet
 * - date: string - Target date (YYYY-MM-DD)
 *
 * Query params:
 * - holidays: string (optional) - Comma-separated list of holiday dates
 */
serviceDemandRoutes.get('/service-demand/:fleetId/:date', async (c) => {
  const requestId = getRequestId(c);
  const fleetId = c.req.param('fleetId');
  const date = c.req.param('date');

  if (!isValidUuid(fleetId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid fleet ID format', requestId), 400);
  }

  // Validate date format
  const dateRegex = /^\d{4}-\d{2}-\d{2}$/;
  if (!dateRegex.test(date)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Date must be in YYYY-MM-DD format', requestId),
      400
    );
  }

  const holidaysParam = c.req.query('holidays');
  const holidays = holidaysParam ? holidaysParam.split(',') : undefined;

  const service = getService();
  const demand = await service.getDemand(fleetId, date, holidays);

  return c.json(
    success({
      fleetId: demand.fleetId,
      fleetCode: demand.fleetCode,
      date: demand.date,
      dayType: demand.dayType,
      minTrainsRequired: demand.minTrainsRequired,
      standbyBuffer: demand.standbyBuffer,
      totalRequired: demand.totalRequired,
      peakAmRequirement: demand.peakAmRequirement,
      middayRequirement: demand.middayRequirement,
      peakPmRequirement: demand.peakPmRequirement,
      eveningRequirement: demand.eveningRequirement,
      source: demand.source,
    })
  );
});

/**
 * POST /service-demand/validate
 *
 * Validate fleet availability against service demand.
 * Returns whether the proposed schedule would violate minimum availability.
 *
 * Body:
 * - fleetId: string (required) - UUID of the fleet
 * - targetDate: string (required) - Date to validate (YYYY-MM-DD)
 * - additionalUnavailable: number (optional) - Number of additional trains that would be unavailable
 * - holidays: string[] (optional) - Array of holiday dates
 */
serviceDemandRoutes.post('/service-demand/validate', async (c) => {
  const requestId = getRequestId(c);
  const body = await c.req.json();

  if (!body.fleetId || !isValidUuid(body.fleetId)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Valid fleetId is required', requestId),
      400
    );
  }

  if (!body.targetDate) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'targetDate is required', requestId),
      400
    );
  }

  const dateRegex = /^\d{4}-\d{2}-\d{2}$/;
  if (!dateRegex.test(body.targetDate)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'targetDate must be in YYYY-MM-DD format', requestId),
      400
    );
  }

  const service = getService();
  const validation = await service.validateAvailability(
    body.fleetId,
    body.targetDate,
    body.additionalUnavailable ?? 0,
    body.holidays
  );

  return c.json(
    success({
      isValid: validation.isValid,
      fleetId: validation.fleetId,
      date: validation.date,
      dayType: validation.dayType,
      totalTrains: validation.totalTrains,
      fitTrains: validation.fitTrains,
      unavailableTrains: validation.unavailableTrains,
      inMaintenanceTrains: validation.inMaintenanceTrains,
      additionalUnavailable: validation.additionalUnavailable,
      availableTrains: validation.availableTrains,
      required: validation.required,
      surplus: validation.surplus,
      severity: validation.severity,
      message: validation.message,
    })
  );
});

/**
 * POST /service-demand/validate-pm
 *
 * Validate a proposed PM schedule against service demand.
 * Checks if scheduling the specified PMs would violate availability.
 *
 * Body:
 * - fleetId: string (required) - UUID of the fleet
 * - proposedPMs: array (required) - Array of proposed PM schedules
 *   - trainId: string (required) - UUID of the train
 *   - targetDate: string (required) - PM target date (YYYY-MM-DD)
 *   - pmCode: string (optional) - PM type code for better error messages
 * - holidays: string[] (optional) - Array of holiday dates
 */
serviceDemandRoutes.post('/service-demand/validate-pm', async (c) => {
  const requestId = getRequestId(c);
  const body = await c.req.json();

  if (!body.fleetId || !isValidUuid(body.fleetId)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Valid fleetId is required', requestId),
      400
    );
  }

  if (!Array.isArray(body.proposedPMs) || body.proposedPMs.length === 0) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'proposedPMs array is required', requestId),
      400
    );
  }

  // Validate proposed PMs
  for (const pm of body.proposedPMs) {
    if (!pm.trainId || !isValidUuid(pm.trainId)) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Each proposedPM requires a valid trainId', requestId),
        400
      );
    }
    if (!pm.targetDate) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'Each proposedPM requires a targetDate', requestId),
        400
      );
    }
  }

  const service = getService();
  const proposedPMs: ProposedPM[] = body.proposedPMs.map((pm: {
    trainId: string;
    targetDate: string;
    pmCode?: string;
    pmTypeId?: string;
    durationDays?: number;
  }) => ({
    trainId: pm.trainId,
    targetDate: pm.targetDate,
    pmCode: pm.pmCode,
    pmTypeId: pm.pmTypeId,
    durationDays: pm.durationDays,
  }));

  const violations = await service.findViolations(body.fleetId, proposedPMs, body.holidays);

  return c.json(
    success({
      isValid: violations.length === 0,
      violations: violations.map((v) => ({
        date: v.date,
        dayType: v.dayType,
        trainId: v.trainId,
        trainNumber: v.trainNumber,
        pmCode: v.pmCode,
        required: v.required,
        available: v.available,
        shortfall: v.shortfall,
        severity: v.severity,
        message: v.message,
      })),
      totalViolations: violations.length,
    })
  );
});

/**
 * POST /service-demand/validate-horizon
 *
 * Validate service demand for a date range (planning horizon).
 * Checks existing scheduled PMs against demand for the entire range.
 *
 * Body:
 * - fleetId: string (required) - UUID of the fleet
 * - startDate: string (required) - Start date (YYYY-MM-DD)
 * - horizonDays: number (required) - Number of days to check
 * - holidays: string[] (optional) - Array of holiday dates
 */
serviceDemandRoutes.post('/service-demand/validate-horizon', async (c) => {
  const requestId = getRequestId(c);
  const body = await c.req.json();

  if (!body.fleetId || !isValidUuid(body.fleetId)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Valid fleetId is required', requestId),
      400
    );
  }

  if (!body.startDate) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'startDate is required', requestId),
      400
    );
  }

  if (!body.horizonDays || body.horizonDays < 1 || body.horizonDays > 365) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'horizonDays must be between 1 and 365', requestId),
      400
    );
  }

  const service = getService();
  const violations = await service.findViolationsInHorizon(
    body.fleetId,
    body.startDate,
    body.horizonDays,
    body.holidays
  );

  return c.json(
    success({
      isValid: violations.length === 0,
      startDate: body.startDate,
      horizonDays: body.horizonDays,
      violatedDates: violations.map((v) => ({
        date: v.date,
        dayType: v.validation.dayType,
        required: v.validation.required,
        available: v.validation.availableTrains,
        shortfall: Math.abs(v.validation.surplus),
        severity: v.validation.severity,
        message: v.validation.message,
      })),
      totalViolations: violations.length,
    })
  );
});

/**
 * GET /service-demand/train/:trainId/can-schedule
 *
 * Check if a specific train can be scheduled for maintenance on a date.
 *
 * Path params:
 * - trainId: string - UUID of the train
 *
 * Query params:
 * - targetDate: string (required) - Date to check (YYYY-MM-DD)
 * - holidays: string (optional) - Comma-separated list of holiday dates
 */
serviceDemandRoutes.get('/service-demand/train/:trainId/can-schedule', async (c) => {
  const requestId = getRequestId(c);
  const trainId = c.req.param('trainId');
  const targetDate = c.req.query('targetDate');

  if (!isValidUuid(trainId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid train ID format', requestId), 400);
  }

  if (!targetDate) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'targetDate query param is required', requestId),
      400
    );
  }

  const holidaysParam = c.req.query('holidays');
  const holidays = holidaysParam ? holidaysParam.split(',') : undefined;

  const service = getService();
  const result = await service.canScheduleTrainForMaintenance(trainId, targetDate, holidays);

  return c.json(
    success({
      canSchedule: result.canSchedule,
      trainId,
      targetDate,
      validation: {
        isValid: result.validation.isValid,
        dayType: result.validation.dayType,
        availableTrains: result.validation.availableTrains,
        required: result.validation.required,
        surplus: result.validation.surplus,
        severity: result.validation.severity,
        message: result.validation.message,
      },
    })
  );
});

// =============================================================================
// Demand Configuration CRUD
// =============================================================================

/**
 * POST /service-demand/config
 *
 * Create a new service demand configuration.
 *
 * Body:
 * - fleetId: string (required) - UUID of the fleet
 * - effectiveDate: string (required) - When this config becomes effective (YYYY-MM-DD)
 * - dayType: string (required) - WEEKDAY | SATURDAY | SUNDAY | HOLIDAY
 * - minTrainsRequired: number (required) - Minimum trains required for service
 * - peakAmRequirement: number (optional) - AM peak requirement
 * - middayRequirement: number (optional) - Midday requirement
 * - peakPmRequirement: number (optional) - PM peak requirement
 * - eveningRequirement: number (optional) - Evening requirement
 * - standbyBuffer: number (optional) - Additional standby trains (default: 2)
 * - notes: string (optional) - Configuration notes
 */
serviceDemandRoutes.post('/service-demand/config', async (c) => {
  const requestId = getRequestId(c);
  const body = await c.req.json();

  if (!body.fleetId || !isValidUuid(body.fleetId)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Valid fleetId is required', requestId),
      400
    );
  }

  if (!body.effectiveDate) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'effectiveDate is required', requestId),
      400
    );
  }

  const validDayTypes = ['WEEKDAY', 'SATURDAY', 'SUNDAY', 'HOLIDAY'];
  if (!body.dayType || !validDayTypes.includes(body.dayType)) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        `dayType must be one of: ${validDayTypes.join(', ')}`,
        requestId
      ),
      400
    );
  }

  if (typeof body.minTrainsRequired !== 'number' || body.minTrainsRequired < 0) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'minTrainsRequired must be a non-negative number', requestId),
      400
    );
  }

  const service = getService();
  const request: CreateDemandRequest = {
    fleetId: body.fleetId,
    effectiveDate: body.effectiveDate,
    dayType: body.dayType,
    minTrainsRequired: body.minTrainsRequired,
    peakAmRequirement: body.peakAmRequirement,
    middayRequirement: body.middayRequirement,
    peakPmRequirement: body.peakPmRequirement,
    eveningRequirement: body.eveningRequirement,
    standbyBuffer: body.standbyBuffer,
    notes: body.notes,
    createdBy: c.get('user')?.id,
  };

  const demand = await service.createDemand(request);

  return c.json(
    success(
      {
        id: demand.id,
        fleetId: demand.fleetId,
        effectiveDate: demand.effectiveDate,
        dayType: demand.dayType,
        minTrainsRequired: demand.minTrainsRequired,
        peakAmRequirement: demand.peakAmRequirement,
        middayRequirement: demand.middayRequirement,
        peakPmRequirement: demand.peakPmRequirement,
        eveningRequirement: demand.eveningRequirement,
        standbyBuffer: demand.standbyBuffer,
        createdAt: demand.createdAt,
      },
      {
        timing: { durationMs: getRequestDuration(c) },
      }
    ),
    201
  );
});

/**
 * GET /service-demand/config
 *
 * List service demand configurations with filtering.
 *
 * Query params:
 * - fleetId: string (optional) - Filter by fleet UUID
 * - dayType: string (optional) - Filter by day type
 * - effectiveDateFrom: string (optional) - Filter by effective date range start
 * - effectiveDateTo: string (optional) - Filter by effective date range end
 * - page: number (optional) - Page number
 * - pageSize: number (optional) - Items per page
 */
serviceDemandRoutes.get('/service-demand/config', async (c) => {
  const service = getService();

  // Parse query filters
  const filters: DemandListFilters = {};
  const fleetId = c.req.query('fleetId');
  const dayType = c.req.query('dayType');
  const effectiveDateFrom = c.req.query('effectiveDateFrom');
  const effectiveDateTo = c.req.query('effectiveDateTo');

  if (fleetId && isValidUuid(fleetId)) {
    filters.fleetId = fleetId;
  }
  if (dayType) {
    const validDayTypes = ['WEEKDAY', 'SATURDAY', 'SUNDAY', 'HOLIDAY'];
    if (validDayTypes.includes(dayType)) {
      filters.dayType = dayType as DemandListFilters['dayType'];
    }
  }
  if (effectiveDateFrom) {
    filters.effectiveDateFrom = effectiveDateFrom;
  }
  if (effectiveDateTo) {
    filters.effectiveDateTo = effectiveDateTo;
  }

  const demands = await service.listDemand(filters);

  // Parse pagination
  const pagination = parsePaginationQuery({
    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
  });

  // Apply pagination in memory
  const startIndex = (pagination.page - 1) * pagination.pageSize;
  const paginatedDemands = demands.slice(startIndex, startIndex + pagination.pageSize);

  return c.json(
    paginatedSuccess(
      paginatedDemands.map((demand) => ({
        id: demand.id,
        fleetId: demand.fleetId,
        effectiveDate: demand.effectiveDate,
        dayType: demand.dayType,
        minTrainsRequired: demand.minTrainsRequired,
        peakAmRequirement: demand.peakAmRequirement,
        middayRequirement: demand.middayRequirement,
        peakPmRequirement: demand.peakPmRequirement,
        eveningRequirement: demand.eveningRequirement,
        standbyBuffer: demand.standbyBuffer,
        notes: demand.notes,
      })),
      {
        page: pagination.page,
        pageSize: pagination.pageSize,
        totalItems: demands.length,
      },
      { durationMs: getRequestDuration(c) }
    )
  );
});

/**
 * GET /service-demand/config/:id
 *
 * Get a specific demand configuration by ID.
 */
serviceDemandRoutes.get('/service-demand/config/:id', async (c) => {
  const requestId = getRequestId(c);
  const id = c.req.param('id');

  if (!isValidUuid(id)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid config ID format', requestId), 400);
  }

  const service = getService();
  const demand = await service.getDemandById(id);

  return c.json(
    success({
      id: demand.id,
      fleetId: demand.fleetId,
      effectiveDate: demand.effectiveDate,
      dayType: demand.dayType,
      minTrainsRequired: demand.minTrainsRequired,
      peakAmRequirement: demand.peakAmRequirement,
      middayRequirement: demand.middayRequirement,
      peakPmRequirement: demand.peakPmRequirement,
      eveningRequirement: demand.eveningRequirement,
      standbyBuffer: demand.standbyBuffer,
      source: demand.source,
      notes: demand.notes,
      createdBy: demand.createdBy,
      createdAt: demand.createdAt,
      updatedAt: demand.updatedAt,
    })
  );
});

/**
 * PATCH /service-demand/config/:id
 *
 * Update a demand configuration.
 *
 * Body: (all optional)
 * - minTrainsRequired: number
 * - peakAmRequirement: number
 * - middayRequirement: number
 * - peakPmRequirement: number
 * - eveningRequirement: number
 * - standbyBuffer: number
 * - notes: string
 */
serviceDemandRoutes.patch('/service-demand/config/:id', async (c) => {
  const requestId = getRequestId(c);
  const id = c.req.param('id');

  if (!isValidUuid(id)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid config ID format', requestId), 400);
  }

  const body = await c.req.json();
  const service = getService();

  const updateData: Partial<CreateDemandRequest> = {};

  if (body.minTrainsRequired !== undefined) {
    if (typeof body.minTrainsRequired !== 'number' || body.minTrainsRequired < 0) {
      return c.json(
        error(ErrorCodes.VALIDATION_ERROR, 'minTrainsRequired must be a non-negative number', requestId),
        400
      );
    }
    updateData.minTrainsRequired = body.minTrainsRequired;
  }

  if (body.peakAmRequirement !== undefined) updateData.peakAmRequirement = body.peakAmRequirement;
  if (body.middayRequirement !== undefined) updateData.middayRequirement = body.middayRequirement;
  if (body.peakPmRequirement !== undefined) updateData.peakPmRequirement = body.peakPmRequirement;
  if (body.eveningRequirement !== undefined) updateData.eveningRequirement = body.eveningRequirement;
  if (body.standbyBuffer !== undefined) updateData.standbyBuffer = body.standbyBuffer;
  if (body.notes !== undefined) updateData.notes = body.notes;

  const demand = await service.updateDemand(id, updateData);

  return c.json(
    success({
      id: demand.id,
      fleetId: demand.fleetId,
      effectiveDate: demand.effectiveDate,
      dayType: demand.dayType,
      minTrainsRequired: demand.minTrainsRequired,
      peakAmRequirement: demand.peakAmRequirement,
      middayRequirement: demand.middayRequirement,
      peakPmRequirement: demand.peakPmRequirement,
      eveningRequirement: demand.eveningRequirement,
      standbyBuffer: demand.standbyBuffer,
      updatedAt: demand.updatedAt,
    })
  );
});

/**
 * DELETE /service-demand/config/:id
 *
 * Delete a demand configuration.
 */
serviceDemandRoutes.delete('/service-demand/config/:id', async (c) => {
  const requestId = getRequestId(c);
  const id = c.req.param('id');

  if (!isValidUuid(id)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid config ID format', requestId), 400);
  }

  const service = getService();
  await service.deleteDemand(id);

  return c.json(success({ deleted: true, id }));
});

// =============================================================================
// Fleet Availability Summary
// =============================================================================

/**
 * GET /service-demand/fleet/:fleetId/summary
 *
 * Get fleet availability summary for today.
 */
serviceDemandRoutes.get('/service-demand/fleet/:fleetId/summary', async (c) => {
  const requestId = getRequestId(c);
  const fleetId = c.req.param('fleetId');

  if (!isValidUuid(fleetId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid fleet ID format', requestId), 400);
  }

  const holidaysParam = c.req.query('holidays');
  const holidays = holidaysParam ? holidaysParam.split(',') : undefined;

  const service = getService();
  const summary = await service.getFleetAvailabilitySummary(fleetId, holidays);

  return c.json(
    success({
      fleetId: summary.fleetId,
      fleetCode: summary.fleetCode,
      totalTrains: summary.totalTrains,
      fitTrains: summary.fitTrains,
      restrictedTrains: summary.restrictedTrains,
      groundedTrains: summary.groundedTrains,
      inMaintenanceTrains: summary.inMaintenanceTrains,
      availableTrains: summary.availableTrains,
      demandConfig: {
        dayType: summary.demandConfig.dayType,
        minTrainsRequired: summary.demandConfig.minTrainsRequired,
        totalRequired: summary.demandConfig.totalRequired,
        source: summary.demandConfig.source,
      },
      utilizationPct: summary.utilizationPct,
      status: summary.status,
    })
  );
});

/**
 * GET /service-demand/summary
 *
 * Get availability summary for all fleets.
 */
serviceDemandRoutes.get('/service-demand/summary', async (c) => {
  const holidaysParam = c.req.query('holidays');
  const holidays = holidaysParam ? holidaysParam.split(',') : undefined;

  const service = getService();
  const summaries = await service.getAllFleetsAvailabilitySummary(holidays);

  return c.json(
    success({
      fleets: summaries.map((s) => ({
        fleetId: s.fleetId,
        fleetCode: s.fleetCode,
        totalTrains: s.totalTrains,
        fitTrains: s.fitTrains,
        availableTrains: s.availableTrains,
        required: s.demandConfig.totalRequired,
        utilizationPct: s.utilizationPct,
        status: s.status,
      })),
      totalFleets: summaries.length,
      criticalCount: summaries.filter((s) => s.status === 'CRITICAL').length,
      warningCount: summaries.filter((s) => s.status === 'WARNING').length,
    })
  );
});

