/**
 * Unavailability Event Routes
 *
 * REST endpoints for managing train unavailability events (outages,
 * corrective maintenance, incidents). These events affect optimizer
 * constraints and train fitness status.
 *
 * @see specs/005-api.md Section 5.8
 * @see specs/004-domain-services.md Section 4.2.5
 */

import { Hono } from 'hono';
import {
  success,
  paginatedSuccess,
  error,
  parsePaginationQuery,
  ErrorCodes,
  type AppVariables,
} from '../types';
import { getRequestId, getRequestDuration } from '../middleware/request-context';
import {
  getUnavailabilityService,
  type CreateEventRequest,
  type ResolveEventRequest,
  type EventListFilters,
} from '../../services/unavailability';
import { isValidUuid } from '../../lib/schemas';

// Singleton service instance
let unavailabilityService: ReturnType<typeof getUnavailabilityService> | null = null;

function getService(): ReturnType<typeof getUnavailabilityService> {
  if (!unavailabilityService) {
    unavailabilityService = getUnavailabilityService();
  }
  return unavailabilityService;
}

export const unavailabilityRoutes = new Hono<{ Variables: AppVariables }>();

// =============================================================================
// Event CRUD
// =============================================================================

/**
 * POST /unavailability/events
 *
 * Create a new unavailability event for a train.
 * This will update the train's fitness status accordingly.
 *
 * Body:
 * - trainId: string (required) - UUID of the affected train
 * - eventType: string (required) - CORRECTIVE | INCIDENT | COLLISION | VANDALISM | EXTERNAL | PLANNED_OUTAGE
 * - restrictionLevel: string (required) - RESTRICTED | GROUNDED
 * - description: string (optional) - Event description
 * - failureCode: string (optional) - Failure code from CMMS
 * - affectedSystem: string (optional) - Affected train system
 * - estimatedRepairHours: number (optional) - Estimated repair time
 * - estimatedReturnDate: string (optional) - Expected return date (YYYY-MM-DD)
 * - sourceSystem: string (optional) - Source system (e.g., 'MAXIMO')
 * - externalReference: string (optional) - External reference (e.g., WO number)
 * - blocksPmScheduling: boolean (optional, default: true) - Prevents PM scheduling
 * - blocksRunAssignment: boolean (optional, default: true) - Prevents run assignment
 */
unavailabilityRoutes.post('/unavailability/events', async (c) => {
  const requestId = getRequestId(c);
  const body = await c.req.json();

  // Validate required fields
  if (!body.trainId || !isValidUuid(body.trainId)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Valid trainId is required', requestId),
      400
    );
  }

  const validEventTypes = ['CORRECTIVE', 'INCIDENT', 'COLLISION', 'VANDALISM', 'EXTERNAL', 'PLANNED_OUTAGE'];
  if (!body.eventType || !validEventTypes.includes(body.eventType)) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        `eventType must be one of: ${validEventTypes.join(', ')}`,
        requestId
      ),
      400
    );
  }

  const validRestrictionLevels = ['RESTRICTED', 'GROUNDED'];
  if (!body.restrictionLevel || !validRestrictionLevels.includes(body.restrictionLevel)) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        `restrictionLevel must be one of: ${validRestrictionLevels.join(', ')}`,
        requestId
      ),
      400
    );
  }

  const service = getService();
  const request: CreateEventRequest = {
    trainId: body.trainId,
    eventType: body.eventType,
    restrictionLevel: body.restrictionLevel,
    description: body.description,
    failureCode: body.failureCode,
    affectedSystem: body.affectedSystem,
    estimatedRepairHours: body.estimatedRepairHours,
    estimatedReturnDate: body.estimatedReturnDate,
    sourceSystem: body.sourceSystem,
    externalReference: body.externalReference,
    blocksPmScheduling: body.blocksPmScheduling ?? true,
    blocksRunAssignment: body.blocksRunAssignment ?? true,
    reportedBy: c.get('user')?.id,
  };

  const event = await service.createEvent(request);

  return c.json(
    success(
      {
        id: event.id,
        trainId: event.trainId,
        eventType: event.eventType,
        status: event.status,
        restrictionLevel: event.restrictionLevel,
        reportedAt: event.reportedAt,
        estimatedReturnDate: event.estimatedReturnDate,
        sourceSystem: event.sourceSystem,
        externalReference: event.externalReference,
        blocksPmScheduling: event.blocksPmScheduling,
        blocksRunAssignment: event.blocksRunAssignment,
        createdAt: event.createdAt,
      },
      {
        timing: { durationMs: getRequestDuration(c) },
      }
    ),
    201
  );
});

/**
 * GET /unavailability/events
 *
 * List unavailability events with filtering.
 *
 * Query params:
 * - trainId: string (optional) - Filter by train UUID
 * - status: string (optional) - ACTIVE | RESOLVED
 * - eventType: string (optional) - Filter by event type
 * - restrictionLevel: string (optional) - RESTRICTED | GROUNDED
 * - sourceSystem: string (optional) - Filter by source system
 * - dateFrom: string (optional) - Filter events reported from this date
 * - dateTo: string (optional) - Filter events reported until this date
 * - blocksPmScheduling: boolean (optional) - Filter by PM blocking status
 * - blocksRunAssignment: boolean (optional) - Filter by run assignment blocking status
 * - page: number (optional) - Page number (default: 1)
 * - pageSize: number (optional) - Items per page (default: 50)
 */
unavailabilityRoutes.get('/unavailability/events', async (c) => {
  const service = getService();

  // Parse query filters
  const filters: EventListFilters = {};
  const trainId = c.req.query('trainId');
  const status = c.req.query('status');
  const eventType = c.req.query('eventType');
  const restrictionLevel = c.req.query('restrictionLevel');
  const sourceSystem = c.req.query('sourceSystem');
  const dateFrom = c.req.query('dateFrom');
  const dateTo = c.req.query('dateTo');
  const blocksPmScheduling = c.req.query('blocksPmScheduling');
  const blocksRunAssignment = c.req.query('blocksRunAssignment');

  if (trainId && isValidUuid(trainId)) {
    filters.trainId = trainId;
  }
  if (status === 'ACTIVE' || status === 'RESOLVED') {
    filters.status = status;
  }
  if (eventType) {
    const validEventTypes = ['CORRECTIVE', 'INCIDENT', 'COLLISION', 'VANDALISM', 'EXTERNAL', 'PLANNED_OUTAGE'];
    if (validEventTypes.includes(eventType)) {
      filters.eventType = eventType as EventListFilters['eventType'];
    }
  }
  if (restrictionLevel === 'RESTRICTED' || restrictionLevel === 'GROUNDED') {
    filters.restrictionLevel = restrictionLevel;
  }
  if (sourceSystem) {
    filters.sourceSystem = sourceSystem;
  }
  if (dateFrom) {
    filters.dateFrom = dateFrom;
  }
  if (dateTo) {
    filters.dateTo = dateTo;
  }
  if (blocksPmScheduling !== undefined) {
    filters.blocksPmScheduling = blocksPmScheduling === 'true';
  }
  if (blocksRunAssignment !== undefined) {
    filters.blocksRunAssignment = blocksRunAssignment === 'true';
  }

  const events = await service.listEvents(filters);

  // Parse pagination
  const pagination = parsePaginationQuery({
    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
  });

  // Apply pagination in memory (service returns all matching events)
  const startIndex = (pagination.page - 1) * pagination.pageSize;
  const paginatedEvents = events.slice(startIndex, startIndex + pagination.pageSize);

  return c.json(
    paginatedSuccess(
      paginatedEvents.map((event) => ({
        id: event.id,
        trainId: event.trainId,
        eventType: event.eventType,
        status: event.status,
        restrictionLevel: event.restrictionLevel,
        reportedAt: event.reportedAt,
        estimatedReturnDate: event.estimatedReturnDate,
        actualReturnDate: event.actualReturnDate,
        resolvedAt: event.resolvedAt,
        sourceSystem: event.sourceSystem,
        externalReference: event.externalReference,
        externalStatus: event.externalStatus,
        description: event.description,
        blocksPmScheduling: event.blocksPmScheduling,
        blocksRunAssignment: event.blocksRunAssignment,
      })),
      {
        page: pagination.page,
        pageSize: pagination.pageSize,
        totalItems: events.length,
      },
      { durationMs: getRequestDuration(c) }
    )
  );
});

/**
 * GET /unavailability/events/:id
 *
 * Get a specific unavailability event by ID with train details.
 */
unavailabilityRoutes.get('/unavailability/events/:id', async (c) => {
  const requestId = getRequestId(c);
  const eventId = c.req.param('id');

  if (!isValidUuid(eventId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid event ID format', requestId), 400);
  }

  const service = getService();
  const event = await service.getEventById(eventId);

  return c.json(
    success({
      id: event.id,
      trainId: event.trainId,
      train: event.train
        ? {
            id: event.train.id,
            trainNumber: event.train.trainNumber,
            fleetId: event.train.fleetId,
            fitnessStatus: event.train.fitnessStatus,
          }
        : null,
      eventType: event.eventType,
      status: event.status,
      restrictionLevel: event.restrictionLevel,
      reportedAt: event.reportedAt,
      estimatedRepairHours: event.estimatedRepairHours,
      estimatedReturnDate: event.estimatedReturnDate,
      actualReturnDate: event.actualReturnDate,
      resolvedAt: event.resolvedAt,
      resolvedBy: event.resolvedBy,
      resolutionNotes: event.resolutionNotes,
      sourceSystem: event.sourceSystem,
      externalReference: event.externalReference,
      externalStatus: event.externalStatus,
      description: event.description,
      failureCode: event.failureCode,
      affectedSystem: event.affectedSystem,
      blocksPmScheduling: event.blocksPmScheduling,
      blocksRunAssignment: event.blocksRunAssignment,
      createdAt: event.createdAt,
      updatedAt: event.updatedAt,
    })
  );
});

/**
 * POST /unavailability/events/:id/resolve
 *
 * Resolve an unavailability event (train returns to service).
 * This will update the train's fitness status if no other active events exist.
 *
 * Body:
 * - actualReturnDate: string (required) - Actual return date (YYYY-MM-DD)
 * - resolutionNotes: string (optional) - Notes about the resolution
 */
unavailabilityRoutes.post('/unavailability/events/:id/resolve', async (c) => {
  const requestId = getRequestId(c);
  const eventId = c.req.param('id');

  if (!isValidUuid(eventId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid event ID format', requestId), 400);
  }

  const body = await c.req.json();

  if (!body.actualReturnDate) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'actualReturnDate is required', requestId),
      400
    );
  }

  // Validate date format
  const dateRegex = /^\d{4}-\d{2}-\d{2}$/;
  if (!dateRegex.test(body.actualReturnDate)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'actualReturnDate must be in YYYY-MM-DD format', requestId),
      400
    );
  }

  const service = getService();
  const request: ResolveEventRequest = {
    eventId,
    actualReturnDate: body.actualReturnDate,
    resolutionNotes: body.resolutionNotes,
    resolvedBy: c.get('user')?.id,
  };

  const event = await service.resolveEvent(request);

  return c.json(
    success({
      id: event.id,
      trainId: event.trainId,
      status: event.status,
      actualReturnDate: event.actualReturnDate,
      resolvedAt: event.resolvedAt,
      resolvedBy: event.resolvedBy,
      resolutionNotes: event.resolutionNotes,
    })
  );
});

// =============================================================================
// Optimizer Constraints
// =============================================================================

/**
 * GET /unavailability/constraints
 *
 * Get active unavailability constraints for the optimizer.
 * Returns train IDs that are blocked from scheduling.
 */
unavailabilityRoutes.get('/unavailability/constraints', async (c) => {
  const service = getService();
  const constraints = await service.queryActiveEvents();

  return c.json(
    success({
      groundedTrainIds: constraints.groundedTrainIds,
      restrictedTrainIds: constraints.restrictedTrainIds,
      blockedFromPmTrainIds: constraints.blockedFromPmTrainIds,
      blockedFromRunAssignmentTrainIds: constraints.blockedFromRunAssignmentTrainIds,
      totalActiveEvents: constraints.totalActiveEvents,
    })
  );
});

/**
 * GET /unavailability/trains/:trainId/events
 *
 * Get active unavailability events for a specific train.
 */
unavailabilityRoutes.get('/unavailability/trains/:trainId/events', async (c) => {
  const requestId = getRequestId(c);
  const trainId = c.req.param('trainId');

  if (!isValidUuid(trainId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid train ID format', requestId), 400);
  }

  const service = getService();
  const events = await service.getActiveEventsForTrain(trainId);

  return c.json(
    success(
      events.map((event) => ({
        id: event.id,
        eventType: event.eventType,
        status: event.status,
        restrictionLevel: event.restrictionLevel,
        reportedAt: event.reportedAt,
        estimatedReturnDate: event.estimatedReturnDate,
        sourceSystem: event.sourceSystem,
        externalReference: event.externalReference,
        description: event.description,
        blocksPmScheduling: event.blocksPmScheduling,
        blocksRunAssignment: event.blocksRunAssignment,
      }))
    )
  );
});

// =============================================================================
// PM Conflict Detection
// =============================================================================

/**
 * GET /unavailability/pm-conflicts
 *
 * Detect conflicts between active unavailability events and scheduled PM.
 *
 * Query params:
 * - dateFrom: string (required) - Start date for conflict check (YYYY-MM-DD)
 * - dateTo: string (required) - End date for conflict check (YYYY-MM-DD)
 */
unavailabilityRoutes.get('/unavailability/pm-conflicts', async (c) => {
  const requestId = getRequestId(c);
  const dateFrom = c.req.query('dateFrom');
  const dateTo = c.req.query('dateTo');

  if (!dateFrom || !dateTo) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'dateFrom and dateTo are required', requestId),
      400
    );
  }

  const service = getService();
  const conflicts = await service.detectPMConflicts(dateFrom, dateTo);

  return c.json(
    success({
      conflicts: conflicts.map((conflict) => ({
        pmScheduleId: conflict.pmScheduleId,
        trainId: conflict.trainId,
        trainNumber: conflict.trainNumber,
        pmCode: conflict.pmCode,
        targetDate: conflict.targetDate,
        unavailabilityEventId: conflict.unavailabilityEventId,
        eventType: conflict.eventType,
        estimatedReturnDate: conflict.estimatedReturnDate,
        severity: conflict.severity,
        message: conflict.message,
      })),
      totalConflicts: conflicts.length,
      highSeverityCount: conflicts.filter((c) => c.severity === 'HIGH').length,
    })
  );
});

// =============================================================================
// Statistics
// =============================================================================

/**
 * GET /unavailability/statistics
 *
 * Get summary statistics for unavailability events.
 */
unavailabilityRoutes.get('/unavailability/statistics', async (c) => {
  const service = getService();
  const stats = await service.getStatistics();

  return c.json(
    success({
      totalActive: stats.totalActive,
      byType: stats.byType,
      byRestrictionLevel: stats.byRestrictionLevel,
      avgResolutionHours: stats.avgResolutionHours,
      trainsAffected: stats.trainsAffected,
    })
  );
});

