   108→
   109→/** Create demand request */
   110→export interface CreateDemandRequest {
   111→  fleetId: string;
   112→  effectiveDate: string;
   113→  dayType: DayType;
   114→  minTrainsRequired: number;
   115→  peakAmRequirement?: number;
   116→  middayRequirement?: number;
