   130→  effectiveDateTo?: string;
   131→}
   132→
   133→/** Fleet availability summary */
   134→export interface FleetAvailabilitySummary {
   135→  fleetId: string;
   136→  fleetCode: string;
   137→  totalTrains: number;
   138→  fitTrains: number;
   139→  restrictedTrains: number;
   140→  groundedTrains: number;
   141→  inMaintenanceTrains: number;
   142→  availableTrains: number;
   143→  demandConfig: DemandConfig;
