   643→  /**
   644→   * Create a new service demand configuration.
   645→   */
   646→  async createDemand(request: CreateDemandRequest): Promise<ServiceDemand> {
   647→    return this.inTransaction('createDemand', async (tx, span) => {
   648→      const {
   649→        fleetId,
   650→        effectiveDate,
   651→        dayType,
   652→        minTrainsRequired,
   653→        peakAmRequirement,
   654→        middayRequirement,
   655→        peakPmRequirement,
   656→        eveningRequirement,
   657→        standbyBuffer = DEFAULT_STANDBY_BUFFER,
   658→        source,
   659→        notes,
   660→        createdBy,
   661→      } = request;
   662→
   663→      span.setAttribute(MmsAttributes.FLEET_ID, fleetId);
   664→      span.setAttribute('demand.dayType', dayType);
   665→      span.setAttribute('demand.effectiveDate', effectiveDate);
   666→
   667→      // Validate fleet exists
   668→      const fleet = await tx.query.fleets.findFirst({
   669→        where: eq(fleets.id, fleetId),
   670→      });
   671→
   672→      if (!fleet) {
   673→        throw new NotFoundError(`Fleet not found: ${fleetId}`, {
   674→          entityType: 'fleet',
   675→          entityId: fleetId,
   676→        });
   677→      }
   678→
   679→      // Validate minTrainsRequired is reasonable
   680→      const [{ totalTrains }] = await tx
   681→        .select({ totalTrains: count() })
   682→        .from(trains)
   683→        .where(and(eq(trains.fleetId, fleetId), eq(trains.active, true)));
   684→
   685→      if (minTrainsRequired > totalTrains) {
   686→        throw new ValidationError(
   687→          `Minimum trains required (${minTrainsRequired}) exceeds fleet size (${totalTrains})`,
   688→          {
   689→            field: 'minTrainsRequired',
   690→            context: { minTrainsRequired, fleetSize: totalTrains },
   691→          }
   692→        );
   693→      }
   694→
   695→      // Check for duplicate (same fleet, date, day type)
   696→      const existing = await tx.query.serviceDemand.findFirst({
   697→        where: and(
   698→          eq(serviceDemand.fleetId, fleetId),
   699→          eq(serviceDemand.effectiveDate, effectiveDate),
   700→          eq(serviceDemand.dayType, dayType)
   701→        ),
   702→      });
   703→
   704→      if (existing) {
   705→        throw new DuplicateError(
   706→          `Service demand already exists for ${fleet.code} on ${effectiveDate} (${dayType})`,
   707→          {
   708→            field: 'effectiveDate',
   709→            value: effectiveDate,
   710→            context: { fleetId, dayType },
   711→          }
   712→        );
   713→      }
   714→
   715→      // Create record
   716→      const demandData: NewServiceDemand = {
   717→        fleetId,
   718→        effectiveDate,
   719→        dayType,
   720→        minTrainsRequired,
   721→        peakAmRequirement: peakAmRequirement ?? null,
   722→        middayRequirement: middayRequirement ?? null,
   723→        peakPmRequirement: peakPmRequirement ?? null,
   724→        eveningRequirement: eveningRequirement ?? null,
   725→        standbyBuffer,
   726→        source: source ?? null,
   727→        notes: notes ?? null,
   728→        createdBy: createdBy ?? null,
   729→      };
   730→
   731→      const [result] = await tx.insert(serviceDemand).values(demandData).returning();
   732→      span.setAttribute('demand.id', result.id);
   733→
   734→      this.log.info(
   735→        {
   736→          demandId: result.id,
   737→          fleetId,
   738→          fleetCode: fleet.code,
   739→          effectiveDate,
   740→          dayType,
   741→          minTrainsRequired,
   742→        },
   743→        `Service demand created: ${fleet.code} ${dayType} requires ${minTrainsRequired} trains from ${effectiveDate}`
   744→      );
   745→
   746→      return result;
   747→    });
   748→  }
