   943→            ? (demandConfig.totalRequired / validation.availableTrains) * 100
   944→            : 0,
   945→        status,
   946→      };
   947→    });
   948→  }
   949→
   950→  /**
   951→   * Get all fleets' availability summaries.
   952→   */
   953→  async getAllFleetsAvailabilitySummary(
   954→    holidays?: string[]
   955→  ): Promise<FleetAvailabilitySummary[]> {
