   969→      );
   970→
   971→      return summaries;
   972→    });
   973→  }
   974→
   975→  // ===========================================================================
   976→  // Helper Methods
   977→  // ===========================================================================
   978→
   979→  /**
   980→   * Determine day type for a given date.
   981→   *
   982→   * @param dateStr - Date string (YYYY-MM-DD)
