/**
 * MMS Service Demand Service
 *
 * Manages fleet availability requirements - a CRITICAL v2.1 service.
 * Service demand is a HARD CONSTRAINT for the optimizer: schedules that
 * violate minimum train availability must be rejected.
 *
 * Key responsibilities:
 * - Define minimum train requirements by fleet, day type, and time period
 * - Validate that proposed PM schedules don't violate availability
 * - Calculate default demand (85% of fleet) when no explicit config exists
 * - Support peak period requirements (AM, midday, PM, evening)
 *
 * Business rules:
 * - Optimizer CANNOT schedule PM that would drop fleet below minTrainsRequired
 * - Day types: WEEKDAY, SATURDAY, SUNDAY, HOLIDAY
 * - Demand records are versioned by effectiveDate (most recent applies)
 * - Peak period requirements are optional but enforced if defined
 *
 * @see specs/003-database-schema.md Section 3.2.1 (Service Demand)
 * @see specs/004-domain-services.md Section 4.2.6 (Service Demand Service)
 */

import { eq, and, sql, desc, lte, count, inArray, gte } from 'drizzle-orm';
import type { SQL } from 'drizzle-orm';
import { BaseService, MmsAttributes } from '../lib/services/base';
import {
  serviceDemand,
  trains,
  fleets,
  pmSchedule,
  type ServiceDemand,
  type NewServiceDemand,
} from '../lib/db/schema';
import {
  NotFoundError,
  ValidationError,
  DuplicateError,
} from '../lib/errors';

// =============================================================================
// Types
// =============================================================================

/** Day type enum values */
export type DayType = 'WEEKDAY' | 'SATURDAY' | 'SUNDAY' | 'HOLIDAY';

/** Time period for peak requirements */
export type TimePeriod = 'PEAK_AM' | 'MIDDAY' | 'PEAK_PM' | 'EVENING' | 'ALL_DAY';

/** Demand configuration for a specific fleet/date */
export interface DemandConfig {
  fleetId: string;
  fleetCode: string;
  date: string;
  dayType: DayType;
  minTrainsRequired: number;
  standbyBuffer: number;
  totalRequired: number; // minTrainsRequired + standbyBuffer
  peakAmRequirement: number | null;
  middayRequirement: number | null;
  peakPmRequirement: number | null;
  eveningRequirement: number | null;
  source: 'CONFIG' | 'DEFAULT';
  sourceRecord: ServiceDemand | null;
}

/** Availability validation result */
export interface AvailabilityValidation {
  isValid: boolean;
  fleetId: string;
  date: string;
  dayType: DayType;
  totalTrains: number;
  fitTrains: number;
  unavailableTrains: number;
  inMaintenanceTrains: number;
  additionalUnavailable: number;
  availableTrains: number;
  required: number;
  surplus: number; // Positive = OK, Negative = VIOLATION
  severity: 'OK' | 'WARNING' | 'VIOLATION';
  message: string;
}

/** Violation detected for proposed PM */
export interface DemandViolation {
  date: string;
  dayType: DayType;
  trainId: string;
  trainNumber: string;
  pmCode: string;
  required: number;
  available: number;
  shortfall: number;
  severity: 'HARD' | 'SOFT';
  message: string;
}

/** Proposed PM for violation checking */
export interface ProposedPM {
  trainId: string;
  targetDate: string;
  pmTypeId?: string;
  pmCode?: string;
  durationDays?: number;
}

/** Create demand request */
export interface CreateDemandRequest {
  fleetId: string;
  effectiveDate: string;
  dayType: DayType;
  minTrainsRequired: number;
  peakAmRequirement?: number;
  middayRequirement?: number;
  peakPmRequirement?: number;
  eveningRequirement?: number;
  standbyBuffer?: number;
  source?: string;
  notes?: string;
  createdBy?: string;
}

/** Query filters for listing demand records */
export interface DemandListFilters {
  fleetId?: string;
  dayType?: DayType | DayType[];
  effectiveDateFrom?: string;
  effectiveDateTo?: string;
}

/** Fleet availability summary */
export interface FleetAvailabilitySummary {
  fleetId: string;
  fleetCode: string;
  totalTrains: number;
  fitTrains: number;
  restrictedTrains: number;
  groundedTrains: number;
  inMaintenanceTrains: number;
  availableTrains: number;
  demandConfig: DemandConfig;
  utilizationPct: number;
  status: 'OK' | 'WARNING' | 'CRITICAL';
}

// =============================================================================
// Constants
// =============================================================================

/** Default fleet availability percentage when no config exists */
const DEFAULT_AVAILABILITY_PCT = 0.85;

/** Default standby buffer */
const DEFAULT_STANDBY_BUFFER = 2;

/** Warning threshold: < this % surplus triggers warning */
const WARNING_THRESHOLD_PCT = 0.10;

// =============================================================================
// Service Demand Service
// =============================================================================

export class ServiceDemandService extends BaseService {
  constructor() {
    super({ name: 'service-demand-service', version: '1.0.0' });
  }

  // ===========================================================================
  // Demand Configuration
  // ===========================================================================

  /**
   * Get demand configuration for a fleet on a specific date.
   *
   * This is the primary method for the optimizer to determine minimum
   * train requirements. It:
   * 1. Determines the day type for the date
   * 2. Finds the most recent effective demand config
   * 3. Falls back to 85% of fleet size if no config exists
   *
   * @param fleetId - Fleet to get demand for
   * @param targetDate - Date to check (YYYY-MM-DD)
   * @param holidays - Optional array of holiday dates (YYYY-MM-DD)
   * @returns Demand configuration for the date
   */
  async getDemand(
    fleetId: string,
    targetDate: string,
    holidays?: string[]
  ): Promise<DemandConfig> {
    return this.traced('getDemand', async (span) => {
      span.setAttribute(MmsAttributes.FLEET_ID, fleetId);
      span.setAttribute('demand.targetDate', targetDate);

      // Verify fleet exists
      const fleet = await this.db.query.fleets.findFirst({
        where: eq(fleets.id, fleetId),
      });

      if (!fleet) {
        throw new NotFoundError(`Fleet not found: ${fleetId}`, {
          entityType: 'fleet',
          entityId: fleetId,
        });
      }

      // Determine day type
      const dayType = this.getDayType(targetDate, holidays);
      span.setAttribute('demand.dayType', dayType);

      // Find most recent effective demand config
      const demandRecord = await this.db.query.serviceDemand.findFirst({
        where: and(
          eq(serviceDemand.fleetId, fleetId),
          eq(serviceDemand.dayType, dayType),
          lte(serviceDemand.effectiveDate, targetDate)
        ),
        orderBy: desc(serviceDemand.effectiveDate),
      });

      if (demandRecord) {
        span.setAttribute('demand.source', 'CONFIG');
        span.setAttribute('demand.minTrains', demandRecord.minTrainsRequired);

        return {
          fleetId,
          fleetCode: fleet.code,
          date: targetDate,
          dayType,
          minTrainsRequired: demandRecord.minTrainsRequired,
          standbyBuffer: demandRecord.standbyBuffer ?? DEFAULT_STANDBY_BUFFER,
          totalRequired:
            demandRecord.minTrainsRequired + (demandRecord.standbyBuffer ?? DEFAULT_STANDBY_BUFFER),
          peakAmRequirement: demandRecord.peakAmRequirement,
          middayRequirement: demandRecord.middayRequirement,
          peakPmRequirement: demandRecord.peakPmRequirement,
          eveningRequirement: demandRecord.eveningRequirement,
          source: 'CONFIG',
          sourceRecord: demandRecord,
        };
      }

      // No config found - calculate default (85% of fleet)
      const defaultDemand = await this.calculateDefaultDemand(fleetId);
      span.setAttribute('demand.source', 'DEFAULT');
      span.setAttribute('demand.minTrains', defaultDemand.minTrainsRequired);

      this.log.warn(
        {
          fleetId,
          fleetCode: fleet.code,
          targetDate,
          dayType,
          calculatedDemand: defaultDemand.minTrainsRequired,
        },
        `No service demand config found for ${fleet.code} on ${targetDate} (${dayType}). Using default 85% of fleet.`
      );

      return {
        fleetId,
        fleetCode: fleet.code,
        date: targetDate,
        dayType,
        minTrainsRequired: defaultDemand.minTrainsRequired,
        standbyBuffer: DEFAULT_STANDBY_BUFFER,
        totalRequired: defaultDemand.minTrainsRequired + DEFAULT_STANDBY_BUFFER,
        peakAmRequirement: null,
        middayRequirement: null,
        peakPmRequirement: null,
        eveningRequirement: null,
        source: 'DEFAULT',
        sourceRecord: null,
      };
    });
  }

  /**
   * Get demand for a specific time period within a day.
   *
   * Used for more granular availability checking during peak hours.
   */
  async getDemandForPeriod(
    fleetId: string,
    targetDate: string,
    period: TimePeriod,
    holidays?: string[]
  ): Promise<number> {
    return this.traced('getDemandForPeriod', async (span) => {
      span.setAttribute(MmsAttributes.FLEET_ID, fleetId);
      span.setAttribute('demand.period', period);

      const demandConfig = await this.getDemand(fleetId, targetDate, holidays);

      if (period === 'ALL_DAY') {
        return demandConfig.totalRequired;
      }

      // Check period-specific requirement, fall back to base requirement
      const periodRequirement = {
        PEAK_AM: demandConfig.peakAmRequirement,
        MIDDAY: demandConfig.middayRequirement,
        PEAK_PM: demandConfig.peakPmRequirement,
        EVENING: demandConfig.eveningRequirement,
      }[period];

      return periodRequirement ?? demandConfig.minTrainsRequired;
    });
  }

  // ===========================================================================
  // Availability Validation
  // ===========================================================================

  /**
   * Validate fleet availability for a date.
   *
   * This is a CRITICAL method for the optimizer. It checks whether the
   * fleet has enough available trains to meet service demand, considering:
   * - Current train fitness status
   * - Active unavailability events
   * - Scheduled PM on that date
   * - Any additional proposed unavailability
   *
   * @param fleetId - Fleet to validate
   * @param targetDate - Date to check
   * @param additionalUnavailable - Number of additional trains that would be unavailable (e.g., proposed PM)
   * @param holidays - Optional array of holiday dates
   * @returns Validation result with detailed breakdown
   */
  async validateAvailability(
    fleetId: string,
    targetDate: string,
    additionalUnavailable: number = 0,
    holidays?: string[]
  ): Promise<AvailabilityValidation> {
    return this.traced('validateAvailability', async (span) => {
      span.setAttribute(MmsAttributes.FLEET_ID, fleetId);
      span.setAttribute('availability.targetDate', targetDate);
      span.setAttribute('availability.additionalUnavailable', additionalUnavailable);

      // Get demand config
      const demandConfig = await this.getDemand(fleetId, targetDate, holidays);

      // Count total and FIT trains in fleet
      const trainCounts = await this.db
        .select({
          total: count(),
          fit: sql<number>`COUNT(*) FILTER (WHERE ${trains.fitnessStatus} = 'FIT')`,
          restricted: sql<number>`COUNT(*) FILTER (WHERE ${trains.fitnessStatus} = 'RESTRICTED')`,
          grounded: sql<number>`COUNT(*) FILTER (WHERE ${trains.fitnessStatus} = 'GROUNDED')`,
        })
        .from(trains)
        .where(and(eq(trains.fleetId, fleetId), eq(trains.active, true)));

      const { total, fit, restricted, grounded } = trainCounts[0];
      const unavailableTrains = restricted + grounded;

      // Count trains in maintenance on that date
      const pmCounts = await this.db
        .select({ inMaintenance: count() })
        .from(pmSchedule)
        .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
        .where(
          and(
            eq(trains.fleetId, fleetId),
            eq(pmSchedule.targetDate, targetDate),
            inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS']),
            sql`${pmSchedule.scenarioId} IS NULL` // Production only
          )
        );

      const inMaintenanceTrains = pmCounts[0]?.inMaintenance ?? 0;

      // Calculate available
      const availableTrains = fit - inMaintenanceTrains - additionalUnavailable;
      const required = demandConfig.totalRequired;
      const surplus = availableTrains - required;

      // Determine severity
      let severity: 'OK' | 'WARNING' | 'VIOLATION';
      let message: string;

      if (surplus < 0) {
        severity = 'VIOLATION';
        message = `HARD CONSTRAINT VIOLATED: ${demandConfig.fleetCode} needs ${required} trains but only ${availableTrains} available (shortfall: ${Math.abs(surplus)})`;
      } else if (surplus < total * WARNING_THRESHOLD_PCT) {
        severity = 'WARNING';
        message = `Low availability margin: ${demandConfig.fleetCode} has ${surplus} surplus trains (${((availableTrains / required) * 100).toFixed(1)}% of requirement)`;
      } else {
        severity = 'OK';
        message = `${demandConfig.fleetCode} availability OK: ${availableTrains} available, ${required} required, ${surplus} surplus`;
      }

      const result: AvailabilityValidation = {
        isValid: surplus >= 0,
        fleetId,
        date: targetDate,
        dayType: demandConfig.dayType,
        totalTrains: total,
        fitTrains: fit,
        unavailableTrains,
        inMaintenanceTrains,
        additionalUnavailable,
        availableTrains,
        required,
        surplus,
        severity,
        message,
      };

      span.setAttribute('availability.isValid', result.isValid);
      span.setAttribute('availability.surplus', surplus);
      span.setAttribute('availability.severity', severity);

      if (severity === 'VIOLATION') {
        this.log.error(
          {
            fleetId,
            fleetCode: demandConfig.fleetCode,
            targetDate,
            required,
            availableTrains,
            surplus,
          },
          message
        );
      } else if (severity === 'WARNING') {
        this.log.warn(
          {
            fleetId,
            fleetCode: demandConfig.fleetCode,
            targetDate,
            required,
            availableTrains,
            surplus,
          },
          message
        );
      }

      return result;
    });
  }

  /**
   * Check if a specific train can be scheduled for maintenance on a date
   * without violating service demand.
   *
   * @param trainId - Train to check
   * @param targetDate - Proposed PM date
   * @param holidays - Optional array of holiday dates
   * @returns true if scheduling this train would NOT violate demand
   */
  async canScheduleTrainForMaintenance(
    trainId: string,
    targetDate: string,
    holidays?: string[]
  ): Promise<{ canSchedule: boolean; validation: AvailabilityValidation }> {
    return this.traced('canScheduleTrainForMaintenance', async (span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
      span.setAttribute('pm.targetDate', targetDate);

      // Get train's fleet
      const train = await this.db.query.trains.findFirst({
        where: eq(trains.id, trainId),
      });

      if (!train) {
        throw new NotFoundError(`Train not found: ${trainId}`, {
          entityType: 'train',
          entityId: trainId,
        });
      }

      // Validate with this train as additional unavailable
      const validation = await this.validateAvailability(
        train.fleetId,
        targetDate,
        1, // This train would become unavailable
        holidays
      );

      return {
        canSchedule: validation.isValid,
        validation,
      };
    });
  }

  // ===========================================================================
  // Violation Detection
  // ===========================================================================

  /**
   * Find all service demand violations for a set of proposed PMs.
   *
   * Used by the optimizer to validate a proposed schedule before committing.
   * Returns detailed violation information for each date/train combination.
   *
   * @param fleetId - Fleet to check
   * @param proposedPMs - Array of proposed PM schedules
   * @param holidays - Optional array of holiday dates
   * @returns Array of violations (empty if no violations)
   */
  async findViolations(
    fleetId: string,
    proposedPMs: ProposedPM[],
    holidays?: string[]
  ): Promise<DemandViolation[]> {
    return this.traced('findViolations', async (span) => {
      span.setAttribute(MmsAttributes.FLEET_ID, fleetId);
      span.setAttribute('violations.proposedCount', proposedPMs.length);

      if (proposedPMs.length === 0) {
        return [];
      }

      // Group proposed PMs by date
      const pmsByDate = new Map<string, ProposedPM[]>();
      for (const pm of proposedPMs) {
        const existing = pmsByDate.get(pm.targetDate) ?? [];
        existing.push(pm);
        pmsByDate.set(pm.targetDate, existing);
      }

      // Get train details for error messages
      const trainIds = [...new Set(proposedPMs.map((p) => p.trainId))];
      const trainMap = new Map<string, { trainNumber: string }>();

      if (trainIds.length > 0) {
        const trainRecords = await this.db.query.trains.findMany({
          where: inArray(trains.id, trainIds),
          columns: { id: true, trainNumber: true },
        });
        for (const t of trainRecords) {
          trainMap.set(t.id, { trainNumber: t.trainNumber });
        }
      }

      // Check each date
      const violations: DemandViolation[] = [];

      for (const [date, pms] of pmsByDate) {
        const validation = await this.validateAvailability(
          fleetId,
          date,
          pms.length, // All proposed PMs on this date
          holidays
        );

        if (!validation.isValid) {
          // Create violation for each PM on this date
          for (const pm of pms) {
            const trainInfo = trainMap.get(pm.trainId);
            violations.push({
              date,
              dayType: validation.dayType,
              trainId: pm.trainId,
              trainNumber: trainInfo?.trainNumber ?? 'unknown',
              pmCode: pm.pmCode ?? 'unknown',
              required: validation.required,
              available: validation.availableTrains + pms.length, // What would be available without these PMs
              shortfall: Math.abs(validation.surplus),
              severity: 'HARD',
              message: `Scheduling ${pm.pmCode ?? 'PM'} for train ${trainInfo?.trainNumber ?? pm.trainId} on ${date} would violate service demand (need ${validation.required}, would have ${validation.availableTrains})`,
            });
          }
        }
      }

      span.setAttribute('violations.count', violations.length);

      if (violations.length > 0) {
        this.log.warn(
          {
            fleetId,
            proposedPMs: proposedPMs.length,
            violations: violations.length,
            violatedDates: [...new Set(violations.map((v) => v.date))],
          },
          `Found ${violations.length} service demand violations for proposed PM schedule`
        );
      }

      return violations;
    });
  }

  /**
   * Find violations for a date range (horizon planning).
   *
   * Checks existing scheduled PMs against service demand for an entire
   * horizon period. Used for drift monitoring and planning validation.
   *
   * @param fleetId - Fleet to check
   * @param startDate - Start of range (YYYY-MM-DD)
   * @param horizonDays - Number of days to check
   * @param holidays - Optional array of holiday dates
   * @returns Array of dates with violations
   */
  async findViolationsInHorizon(
    fleetId: string,
    startDate: string,
    horizonDays: number,
    holidays?: string[]
  ): Promise<{ date: string; validation: AvailabilityValidation }[]> {
    return this.traced('findViolationsInHorizon', async (span) => {
      span.setAttribute(MmsAttributes.FLEET_ID, fleetId);
      span.setAttribute('horizon.startDate', startDate);
      span.setAttribute('horizon.days', horizonDays);

      const violations: { date: string; validation: AvailabilityValidation }[] = [];
      const start = new Date(startDate);

      for (let i = 0; i < horizonDays; i++) {
        const checkDate = new Date(start);
        checkDate.setDate(checkDate.getDate() + i);
        const dateStr = checkDate.toISOString().split('T')[0];

        const validation = await this.validateAvailability(
          fleetId,
          dateStr,
          0, // Check existing schedule only
          holidays
        );

        if (!validation.isValid) {
          violations.push({ date: dateStr, validation });
        }
      }

      span.setAttribute('horizon.violations', violations.length);
      return violations;
    });
  }

  // ===========================================================================
  // CRUD Operations
  // ===========================================================================

  /**
   * Create a new service demand configuration.
   */
  async createDemand(request: CreateDemandRequest): Promise<ServiceDemand> {
    return this.inTransaction('createDemand', async (tx, span) => {
      const {
        fleetId,
        effectiveDate,
        dayType,
        minTrainsRequired,
        peakAmRequirement,
        middayRequirement,
        peakPmRequirement,
        eveningRequirement,
        standbyBuffer = DEFAULT_STANDBY_BUFFER,
        source,
        notes,
        createdBy,
      } = request;

      span.setAttribute(MmsAttributes.FLEET_ID, fleetId);
      span.setAttribute('demand.dayType', dayType);
      span.setAttribute('demand.effectiveDate', effectiveDate);

      // Validate fleet exists
      const fleet = await tx.query.fleets.findFirst({
        where: eq(fleets.id, fleetId),
      });

      if (!fleet) {
        throw new NotFoundError(`Fleet not found: ${fleetId}`, {
          entityType: 'fleet',
          entityId: fleetId,
        });
      }

      // Validate minTrainsRequired is reasonable
      const [{ totalTrains }] = await tx
        .select({ totalTrains: count() })
        .from(trains)
        .where(and(eq(trains.fleetId, fleetId), eq(trains.active, true)));

      if (minTrainsRequired > totalTrains) {
        throw new ValidationError(
          `Minimum trains required (${minTrainsRequired}) exceeds fleet size (${totalTrains})`,
          {
            field: 'minTrainsRequired',
            context: { minTrainsRequired, fleetSize: totalTrains },
          }
        );
      }

      // Check for duplicate (same fleet, date, day type)
      const existing = await tx.query.serviceDemand.findFirst({
        where: and(
          eq(serviceDemand.fleetId, fleetId),
          eq(serviceDemand.effectiveDate, effectiveDate),
          eq(serviceDemand.dayType, dayType)
        ),
      });

      if (existing) {
        throw new DuplicateError(
          `Service demand already exists for ${fleet.code} on ${effectiveDate} (${dayType})`,
          {
            field: 'effectiveDate',
            value: effectiveDate,
            context: { fleetId, dayType },
          }
        );
      }

      // Create record
      const demandData: NewServiceDemand = {
        fleetId,
        effectiveDate,
        dayType,
        minTrainsRequired,
        peakAmRequirement: peakAmRequirement ?? null,
        middayRequirement: middayRequirement ?? null,
        peakPmRequirement: peakPmRequirement ?? null,
        eveningRequirement: eveningRequirement ?? null,
        standbyBuffer,
        source: source ?? null,
        notes: notes ?? null,
        createdBy: createdBy ?? null,
      };

      const [result] = await tx.insert(serviceDemand).values(demandData).returning();
      span.setAttribute('demand.id', result.id);

      this.log.info(
        {
          demandId: result.id,
          fleetId,
          fleetCode: fleet.code,
          effectiveDate,
          dayType,
          minTrainsRequired,
        },
        `Service demand created: ${fleet.code} ${dayType} requires ${minTrainsRequired} trains from ${effectiveDate}`
      );

      return result;
    });
  }

  /**
   * Update an existing service demand configuration.
   */
  async updateDemand(
    id: string,
    data: Partial<Omit<CreateDemandRequest, 'fleetId' | 'effectiveDate' | 'dayType'>>
  ): Promise<ServiceDemand> {
    return this.inTransaction('updateDemand', async (tx, span) => {
      span.setAttribute('demand.id', id);

      const existing = await tx.query.serviceDemand.findFirst({
        where: eq(serviceDemand.id, id),
        with: { fleet: true },
      });

      if (!existing) {
        throw new NotFoundError(`Service demand not found: ${id}`, {
          entityType: 'service_demand',
          entityId: id,
        });
      }

      // Validate minTrainsRequired if changing
      if (data.minTrainsRequired !== undefined) {
        const [{ totalTrains }] = await tx
          .select({ totalTrains: count() })
          .from(trains)
          .where(and(eq(trains.fleetId, existing.fleetId), eq(trains.active, true)));

        if (data.minTrainsRequired > totalTrains) {
          throw new ValidationError(
            `Minimum trains required (${data.minTrainsRequired}) exceeds fleet size (${totalTrains})`,
            {
              field: 'minTrainsRequired',
              context: { minTrainsRequired: data.minTrainsRequired, fleetSize: totalTrains },
            }
          );
        }
      }

      const [result] = await tx
        .update(serviceDemand)
        .set({
          ...data,
          updatedAt: new Date(),
        })
        .where(eq(serviceDemand.id, id))
        .returning();

      this.log.info(
        { demandId: id, updates: data },
        'Service demand updated'
      );

      return result;
    });
  }

  /**
   * Get a demand configuration by ID.
   */
  async getDemandById(id: string): Promise<ServiceDemand> {
    return this.traced('getDemandById', async (span) => {
      span.setAttribute('demand.id', id);

      const result = await this.db.query.serviceDemand.findFirst({
        where: eq(serviceDemand.id, id),
      });

      if (!result) {
        throw new NotFoundError(`Service demand not found: ${id}`, {
          entityType: 'service_demand',
          entityId: id,
        });
      }

      return result;
    });
  }

  /**
   * List demand configurations with filtering.
   */
  async listDemand(filters?: DemandListFilters): Promise<ServiceDemand[]> {
    return this.traced('listDemand', async (span) => {
      const conditions: SQL<unknown>[] = [];

      if (filters?.fleetId) {
        conditions.push(eq(serviceDemand.fleetId, filters.fleetId));
      }
      if (filters?.dayType) {
        if (Array.isArray(filters.dayType)) {
          conditions.push(inArray(serviceDemand.dayType, filters.dayType));
        } else {
          conditions.push(eq(serviceDemand.dayType, filters.dayType));
        }
      }
      if (filters?.effectiveDateFrom) {
        conditions.push(gte(serviceDemand.effectiveDate, filters.effectiveDateFrom));
      }
      if (filters?.effectiveDateTo) {
        conditions.push(lte(serviceDemand.effectiveDate, filters.effectiveDateTo));
      }

      const result = await this.db.query.serviceDemand.findMany({
        where: conditions.length > 0 ? and(...conditions) : undefined,
        orderBy: [desc(serviceDemand.effectiveDate), desc(serviceDemand.dayType)],
      });

      span.setAttribute('result.count', result.length);
      return result;
    });
  }

  /**
   * Delete a demand configuration.
   */
  async deleteDemand(id: string): Promise<void> {
    return this.inTransaction('deleteDemand', async (tx, span) => {
      span.setAttribute('demand.id', id);

      const existing = await tx.query.serviceDemand.findFirst({
        where: eq(serviceDemand.id, id),
      });

      if (!existing) {
        throw new NotFoundError(`Service demand not found: ${id}`, {
          entityType: 'service_demand',
          entityId: id,
        });
      }

      await tx.delete(serviceDemand).where(eq(serviceDemand.id, id));

      this.log.info(
        { demandId: id, fleetId: existing.fleetId, dayType: existing.dayType },
        'Service demand deleted'
      );
    });
  }

  // ===========================================================================
  // Summary & Reports
  // ===========================================================================

  /**
   * Get fleet availability summary for today.
   */
  async getFleetAvailabilitySummary(
    fleetId: string,
    holidays?: string[]
  ): Promise<FleetAvailabilitySummary> {
    return this.traced('getFleetAvailabilitySummary', async (span) => {
      span.setAttribute(MmsAttributes.FLEET_ID, fleetId);

      const today = new Date().toISOString().split('T')[0];
      const demandConfig = await this.getDemand(fleetId, today, holidays);
      const validation = await this.validateAvailability(fleetId, today, 0, holidays);

      // Get detailed counts
      const trainCounts = await this.db
        .select({
          fit: sql<number>`COUNT(*) FILTER (WHERE ${trains.fitnessStatus} = 'FIT')`,
          restricted: sql<number>`COUNT(*) FILTER (WHERE ${trains.fitnessStatus} = 'RESTRICTED')`,
          grounded: sql<number>`COUNT(*) FILTER (WHERE ${trains.fitnessStatus} = 'GROUNDED')`,
        })
        .from(trains)
        .where(and(eq(trains.fleetId, fleetId), eq(trains.active, true)));

      const { fit, restricted, grounded } = trainCounts[0];

      // Determine status
      let status: 'OK' | 'WARNING' | 'CRITICAL';
      if (!validation.isValid) {
        status = 'CRITICAL';
      } else if (validation.severity === 'WARNING') {
        status = 'WARNING';
      } else {
        status = 'OK';
      }

      return {
        fleetId,
        fleetCode: demandConfig.fleetCode,
        totalTrains: validation.totalTrains,
        fitTrains: fit,
        restrictedTrains: restricted,
        groundedTrains: grounded,
        inMaintenanceTrains: validation.inMaintenanceTrains,
        availableTrains: validation.availableTrains,
        demandConfig,
        utilizationPct:
          validation.availableTrains > 0
            ? (demandConfig.totalRequired / validation.availableTrains) * 100
            : 0,
        status,
      };
    });
  }

  /**
   * Get all fleets' availability summaries.
   */
  async getAllFleetsAvailabilitySummary(
    holidays?: string[]
  ): Promise<FleetAvailabilitySummary[]> {
    return this.traced('getAllFleetsAvailabilitySummary', async (span) => {
      const allFleets = await this.db.query.fleets.findMany({
        where: eq(fleets.active, true),
      });

      const summaries = await Promise.all(
        allFleets.map((f) => this.getFleetAvailabilitySummary(f.id, holidays))
      );

      span.setAttribute('result.count', summaries.length);
      span.setAttribute(
        'result.criticalCount',
        summaries.filter((s) => s.status === 'CRITICAL').length
      );

      return summaries;
    });
  }

  // ===========================================================================
  // Helper Methods
  // ===========================================================================

  /**
   * Determine day type for a given date.
   *
   * @param dateStr - Date string (YYYY-MM-DD)
   * @param holidays - Optional array of holiday dates
   * @returns Day type enum value
   */
  getDayType(dateStr: string, holidays?: string[]): DayType {
    // Check if it's a holiday first
    if (holidays?.includes(dateStr)) {
      return 'HOLIDAY';
    }

    const date = new Date(dateStr);
    const dayOfWeek = date.getDay();

    if (dayOfWeek === 0) return 'SUNDAY';
    if (dayOfWeek === 6) return 'SATURDAY';
    return 'WEEKDAY';
  }

  /**
   * Calculate default demand when no config exists.
   * Uses 85% of fleet size as the default requirement.
   */
  private async calculateDefaultDemand(
    fleetId: string
  ): Promise<{ minTrainsRequired: number }> {
    const [{ totalTrains }] = await this.db
      .select({ totalTrains: count() })
      .from(trains)
      .where(and(eq(trains.fleetId, fleetId), eq(trains.active, true)));

    const minTrainsRequired = Math.ceil(totalTrains * DEFAULT_AVAILABILITY_PCT);

    return { minTrainsRequired };
  }
}

// =============================================================================
// Singleton Export
// =============================================================================

let serviceDemandServiceInstance: ServiceDemandService | null = null;

export function getServiceDemandService(): ServiceDemandService {
  if (!serviceDemandServiceInstance) {
    serviceDemandServiceInstance = new ServiceDemandService();
  }
  return serviceDemandServiceInstance;
}

export default ServiceDemandService;

/**
 * MMS Route Utilization Service
 *
 * Provides route-specific daily mileage rates for accurate long-term projections.
 * Critical for PM scheduling as fleet-wide averages can result in 60,000+ km
 * projection error over the 12-year contract period.
 *
 * Key responsibilities:
 * - Retrieve route-specific utilization profiles
 * - Calculate expected daily km for trains with fallback hierarchy
 * - Project cumulative mileage over time horizons
 * - Apply seasonal multipliers for peak/off-peak periods
 *
 * Fallback hierarchy (in priority order):
 * 1. Route-specific profile from route_utilization_profiles table
 * 2. Fleet-wide average from last 30 days of mileage readings
 * 3. System default: 250 km/day (conservative estimate)
 *
 * @see specs/004-domain-services.md Section 4.2.7 (Route Utilization Service)
 * @see specs/003-database-schema.md Section 3.2.2 (Route Utilization Profiles)
 */

import { eq, and, sql, desc, lte, gte, avg, inArray } from 'drizzle-orm';
import type { SQL } from 'drizzle-orm';
import { addDays } from 'date-fns';
import { BaseService, MmsAttributes } from '../lib/services/base';
import {
  routeUtilizationProfiles,
  trains,
  fleets,
  routes,
  mileageReadings,
  runAssignments,
  type RouteUtilizationProfile,
  type NewRouteUtilizationProfile,
} from '../lib/db/schema';
import { NotFoundError, ValidationError, DuplicateError } from '../lib/errors';
import { addJob, QUEUE_NAMES } from '../lib/queue';

